/* ==========================================================================
   Yellowstone Road Conditions Map — app.min.js
   NPMap.js / Leaflet-based road status map for visitor center displays.

   This file is loaded by dev.html and initializes the interactive map.
   It is embedded as an iframe in the YELL Wall Monitor grid display.

   Data sources (all from carto.nps.gov):
     - Road open/closed statuses
     - Road incidents
     - Snowplow locations (reserved for future use)
     - Construction zones
     - Destinations (filtered to VCs and entrance stations only)
     - Road messages

   The visitor center key is passed in via URL query parameter:
     dev.html?key=YOUR_NPMAP_ID
   This is used to determine the "You Are Here" destination highlight.

   To add a new visitor center to the You Are Here map, add an entry to
   youAreHereMap below using the npmap_id as the key and the destination
   name (as it appears in the GeoJSON) as the value.
   ========================================================================== */

var s = document.createElement("script"), App, Handlers, NPMap;

// ---------------------------------------------------------------------------
// Destination configuration
// ---------------------------------------------------------------------------

// Only these destinations will appear on the map.
// Key: exact name from yellowstone_destinations.geojson
// Value: display name shown in the label
var destinationAllowList = {
    'Mammoth Hot Springs': 'Mammoth Hot Springs',
    'Old Faithful':        'Old Faithful',
    'Canyon Village':      'Canyon Village',
    'Grant Village':       'Grant Village',
    'Norris Junction':     'Norris',
    'Fishing Bridge':      'Fishing Bridge',
    'West Entrance':       'West Entrance',
    'North Entrance':      'North Entrance',
    'East Entrance':       'East Entrance',
    'South Entrance':      'South Entrance',
    'Northeast Entrance':  'Northeast Entrance'
};

// Maps each visitor center npmap_id to its destination name.
// Used to highlight the current location with a green label.
// To add a new location, add its npmap_id and matching destination name.
var youAreHereMap = {
    '7835242a-1be7-4303-b421-33635e278be5': 'Mammoth Hot Springs',
    'db52c6c7c3d4de64e1d0605f00dc2e52':      'Grant Village',
    '865e66fd2944ffa90d0bf5cc84d3d066':      'Canyon Village',
    'a3719f751fd4cd190ea2ea84b8e8b608':      'Old Faithful',
    '0cb2b32ffdbd363ac82caa91760301cb':      'West Entrance',
    'd4da254f3b3fdba0a077894ba3381f71':      'Fishing Bridge'
};

// Read visitor center key passed in from wall monitor iframe src URL
var params            = new URLSearchParams(window.location.search);
var activeKey         = params.get('key') || '';
var activeDestination = youAreHereMap[activeKey] || '';

// Entrance stations receive the entrance station icon instead of the VC icon.
// To add or remove an entrance station, update this array.
var entranceStations = [
    'West Entrance',
    'North Entrance',
    'East Entrance',
    'South Entrance',
    'Northeast Entrance'
];

// NPS Symbol Library icon URLs.
// To use a different size, change the number at the end (e.g. -14 or -22).
var iconEntranceUrl   = 'https://raw.githubusercontent.com/nationalparkservice/symbol-library/refs/heads/master/src/shielded/entrance-station-white-22.svg';
var iconVisitorCtrUrl = 'https://raw.githubusercontent.com/nationalparkservice/symbol-library/refs/heads/master/src/shielded/visitor-center-white-22.svg';
var iconVisitorCtrSmUrl = 'https://raw.githubusercontent.com/nationalparkservice/symbol-library/refs/heads/master/src/shielded/visitor-center-white-22.svg';

// ---------------------------------------------------------------------------
// App — main application object
// ---------------------------------------------------------------------------
App = {
    construction: [],
    first: !0,
    hasOverSnow: !1,
    incidents: [],
    messages: [],
    overlays: [
        // Index 0: Roads — colored green (open) or grey (closed)
        {
            name: "Roads",
            popup: function(e) {
                var s = '<div class="title">' + e.name,
                    o = e.npmap_id;
                if (e.name_segment) {
                    s += "<br>" + e.name_segment;
                }
                s += '</div><div class="content"><div class="description"><p>Road Status:</p>';
                if (e.public_open_to_oversnow_vehicles && e.public_open_to_wheeled_vehicles) {
                    s += "<ul><li>Wheeled Vehicles: " + App.getYesNo(e.public_open_to_wheeled_vehicles) + "</li><li>Over-snow Vehicles: " + App.getYesNo(e.public_open_to_oversnow_vehicles) + "</li></ul>";
                } else {
                    s += "<ul><li>Wheeled Vehicles: " + App.getYesNo(e.public_open_to_wheeled_vehicles) + "</li></ul>";
                }
                if (e.public_open_to_oversnow_vehicles || e.public_open_to_wheeled_vehicles) {
                    var a,
                        t = App.get("messages", o);
                    if (t.length) {
                        s += "<p>Messages:</p><ul>";
                        for (a = 0; a < t.length; a++) {
                            s += "<li>" + t[a] + "</li>";
                        }
                        s += "</ul>";
                    }
                }
                return s;
            },
            styles: {
                line: function(e) {
                    var s = {
                        "stroke-width": 5,
                        "stroke-opacity": 1
                    };
                    return e[App.type] ? s.stroke = "#267018" : s.stroke = "#B3B3B3",
                    s;
                }
            },
            type: "geojson",
            vector: !1,
            url: "https://carto.nps.gov/user/nps-yell/api/v2/sql?cb=" + (new Date).getTime() + "&q=SELECT roads.name,roads.name_segment,roads.npmap_id,roads.the_geom,road_statuses.cartodb_id,road_statuses.public_open_to_oversnow_vehicles,road_statuses.public_open_to_wheeled_vehicles FROM roads,road_statuses WHERE road_statuses.archived=false AND roads.npmap_id=road_statuses.npmap_id&format=geojson"
        },
        // Index 1: Incidents — marked with incident icon
        {
            name: "Incidents",
            popup: {
                description: "{{type}}",
                title: "{{name}}{{#if name_segment}}<br>({{name_segment}}){{/if}}"
            },
            styles: {
                point: {
                    "marker-color": "994660",
                    "marker-size": "medium"
                }
            },
            type: "geojson",
            vector: !1,
            url: "https://carto.nps.gov/user/nps-yell/api/v2/sql?cb=" + (new Date).getTime() + "&q=SELECT roads.name,roads.npmap_id,roads.name_segment,road_incidents.cartodb_id,road_incidents.the_geom,road_incidents.type FROM roads,road_incidents WHERE road_incidents.archived=false AND roads.npmap_id=road_incidents.npmap_id&format=geojson"
        },
        // Index 2: Snowplows — reserved for future use, currently returns empty
        {
            name: "Snowplows",
            popup: {
                description: function(e) {
                    return e.message && "null" !== e.message ? e.message : "No message.";
                },
                title: "{{name}}{{#if name_segment}}<br>({{name_segment}}){{/if}}"
            },
            styles: {
                point: {
                    "marker-color": "68a7f9",
                    "marker-size": "medium"
                }
            },
            type: "geojson",
            vector: !1,
            url: "https://carto.nps.gov/user/nps-yell/api/v2/sql?cb=" + (new Date).getTime() + "&q=SELECT roads.name,roads.npmap_id,roads.name_segment,road_snowplows.cartodb_id,road_snowplows.the_geom,road_snowplows.message FROM roads,road_snowplows WHERE road_snowplows.archived=false AND roads.npmap_id=road_snowplows.npmap_id&format=geojson"
        },
        // Index 3: Construction zones
        {
            name: "Construction",
            popup: {
                description: function(e) {
                    return e.message && "null" !== e.message ? e.message : "No message.";
                },
                title: "{{name}}{{#if name_segment}}<br>({{name_segment}}){{/if}}"
            },
            styles: {
                point: {
                    iconAnchor: [10, 25],
                    iconRetinaUrl: "/maps/yell/live/kiosk/maps/roads/assets/img/construction@2x.png",
                    iconSize: [20, 50],
                    iconUrl: "/maps/yell/live/kiosk/maps/roads/assets/img/construction.png",
                    popupAnchor: [2, -25]
                }
            },
            type: "geojson",
            vector: !1,
            url: "https://carto.nps.gov/user/nps-yell/api/v2/sql?cb=" + (new Date).getTime() + "&q=SELECT roads.name,roads.npmap_id,roads.name_segment,road_construction.cartodb_id,road_construction.the_geom,road_construction.message FROM roads,road_construction WHERE road_construction.archived=false AND roads.npmap_id=road_construction.npmap_id&format=geojson"
        },
        // Index 4: Destinations — filtered to VCs and entrance stations only
        {
            name: "Destinations",
            popup: {
                description: "{{#if to}}<p>Average drive time:</p><ul>{{#each to}}<li>To {{name}}: <strong>{{time}}</strong></li>{{/each}}</ul>{{/if}}",
                title: "{{name}}"
            },
            styles: {
                point: {
                    iconAnchor: [7.5, 7.5],
                    iconSize: [15, 15],
                    iconRetinaUrl: "/maps/yell/live/kiosk/maps/roads/assets/img/black-dot@2x.png",
                    iconUrl: "/maps/yell/live/kiosk/maps/roads/assets/img/black-dot.png",
                    popupAnchor: [2, -7.5]
                }
            },
            type: "geojson",
            vector: !1,
            url: "https://nationalparkservice.github.io/data/projects/yellowstone_national_park/live/yellowstone_destinations.geojson"
        }
    ],
    ready: 0,
    roads: [],
    snowplows: [],
    type: "public_open_to_wheeled_vehicles",

    // Toggle between wheeled and over-snow vehicle road status display
    changeType: function(e) {
        e !== App.type && (App.type = e,
        NPMap.config.overlays[0].L.eachLayer(function(e) {
            var s = { weight: 3 };
            !0 === e.feature.properties[App.type] ? s.color = "#267018" : s.color = "#B3B3B3",
            e.setStyle(s);
        }));
    },

    // Get all features from a named array that match a given npmap_id
    get: function(e, s) {
        var o = App[e], a = [];
        if (o.length) {
            for (var t = 0; t < o.length; t++) {
                var n = o[t].feature.properties;
                n.npmap_id === s && a.push(n);
            }
        }
        return a;
    },

    // Returns a colored Yes/No span for road status display
    getYesNo: function(e) {
        var s = '<span style="color:';
        return (s += e ? '#267018;">Yes' : '#B3B3B3;">No') + "</span>";
    },

    // Main overlay loader — called by NPMap.js after map initializes
    loadOverlays: function(e) {
        var s;
        App.ready = 0;

        // Fit map to show all of Yellowstone NP on load.
        // Adjust these coordinates if the initial map position needs to change.
        NPMap.config.L.fitBounds([[43.20, -111.50], [45.90, -109.55]]);

        // Load all overlay layers
        for (var o = 0; o < App.overlays.length; o++) {
            var a = App.overlays[o];
            "object" == typeof a.L && NPMap.config.L.removeLayer(a.L);
            a.L = L.npmap.layer.geojson(a).on("ready", Handlers.handleReady).addTo(NPMap.config.L);
        }

        // Poll until all overlays have fired their ready event.
        // Uses >= instead of === to avoid race condition where ready count
        // skips a value if multiple overlays load between poll intervals.
        s = setInterval(function() {
            if (App.ready >= App.overlays.length) {
                clearInterval(s);

                // Filter destinations layer to approved list,
                // replace default dots with NPS symbol icons and styled labels
                App.overlays[4].L.eachLayer(function(layer) {
                    var name = layer.feature.properties.name;

                    // Remove destinations not in the allow list
                    if (!destinationAllowList[name]) {
                        App.overlays[4].L.removeLayer(layer);
                        return;
                    }

                    var displayName  = destinationAllowList[name];
                    var isHere       = (displayName === activeDestination || name === activeDestination);
                    var isEntrance   = entranceStations.indexOf(displayName) > -1;
                    var iconUrl      = isEntrance ? iconEntranceUrl : iconVisitorCtrUrl;

                    // Label style: green background for current VC, dark for all others
                    var style = isHere
                        ? "font-weight:bold;font-family:Arial,sans-serif;color:#fff;white-space:nowrap;font-size:13px;background:#267018;padding:2px 5px;border-radius:2px;"
                        : "font-weight:bold;font-family:Arial,sans-serif;color:#fff;white-space:nowrap;font-size:13px;background:rgba(0,0,0,0.7);padding:2px 5px;border-radius:2px;";

                    // Per-location label offsets to avoid overlapping roads.
                    // Adjust left/top values here if labels need repositioning.
                    var labelOffset = (displayName === 'Mammoth Hot Springs') ? 'position:absolute;left:26px;top:-10px;'
                        : (displayName === 'Norris')         ? 'position:absolute;right:25px;top:-6px;'
                        : (displayName === 'Old Faithful')   ? 'position:absolute;left:25px;top:-16px;'
                        : (displayName === 'Fishing Bridge') ? 'position:absolute;left:25px;top:-15px;'
                        : 'position:absolute;left:26px;top:-6px;';

                    // West Entrance gets a stacked VC icon and West Yellowstone label
                    var westYellowstoneExtra = (displayName === 'West Entrance')
                        ? "<img src='" + iconVisitorCtrUrl + "' style='width:22px;height:22px;position:absolute;left:-25px;top:0px;'>"
                          + "<span style=\"position:absolute;left:-45px;top:26px;" + style + "\">West Yellowstone</span>"
                        : "";

                    // Entrance stations show icon only (no label) — they are self-explanatory.
                    // Visitor centers show icon + label.
                    var labelHtml = isEntrance
                        ? "<div style='position:relative;display:inline-block;'>"
                          + "<img src='" + iconUrl + "' style='width:22px;height:22px;'>"
                          + westYellowstoneExtra
                          + "</div>"
                        : "<div style='position:relative;display:inline-block;'>"
                          + "<img src='" + iconUrl + "' style='width:22px;height:22px;'>"
                          + "<span style=\"" + labelOffset + style + "\">" + displayName + "</span>"
                          + "</div>";

                    L.marker(layer.getLatLng(), {
                        icon: L.divIcon({
                            className: "",
                            html: labelHtml,
                            iconAnchor: [11, 11]
                        }),
                        interactive: false
                    }).addTo(NPMap.config.L);
                });

                // Fetch road messages and build legend
                L.npmap.util._.reqwest({
                    success: function(s) {
                        var o, a = ["construction", "incidents", "snowplows"],
                            t = '<div style="min-width:100px;"><ul>'
                             + '<li style="height:28px;"><img src="https://yelldigital.github.io/yell-vc-info-screen/maps/yell/live/kiosk/maps/roads/assets/img/open-public-wheeled@2x.png" style="height:6px;margin-bottom:3px;margin-right:1px;width:25px;"> Open</li>'
                             + '<li style="height:28px;"><img src="https://yelldigital.github.io/yell-vc-info-screen/maps/yell/live/kiosk/maps/roads/assets/img/closed-all@2x.png" style="height:6px;margin-bottom:3px;margin-right:1px;width:25px;"> Closed</li>';

                        if (s.data && s.data.rows && s.data.rows.length) {
                            App.messages = s.data.rows;
                        }

                        for (o = 0; o < App.roads.length; o++) {
                            if (App.roads[o].public_open_to_oversnow_vehicles) {
                                App.hasOverSnow = !0;
                                break;
                            }
                        }

                        for (o = 0; o < a.length; o++) {
                            var n = a[o];
                            if (App[n].length) {
                                t += '<li><div style="height:30px;overflow:hidden;">'
                                   + '<img src="/maps/yell/live/kiosk/maps/roads/assets/img/' + n + '@2x.png" style="float:left;margin-left:4px;width:18px;">'
                                   + '<div style="float:left;margin-left:8px;">' + (n.charAt(0).toUpperCase() + n.slice(1)) + "</div>"
                                   + "</div></li>";
                            }
                        }

                        t += "</ul></div>";

                        // Show over-snow toggle if park has over-snow vehicle routes
                        if (App.hasOverSnow) {
                            t += '<form>'
                               + '<div class="radio"><label><input type="radio" name="closure-types" onclick="App.changeType(this.value);" value="public_open_to_wheeled_vehicles" checked> Wheeled Vehicles</label></div>'
                               + '<div class="radio"><label><input type="radio" name="closure-types" onclick="App.changeType(this.value);" value="public_open_to_oversnow_vehicles"> Over-snow Vehicles</label></div>'
                               + '</form>';
                        }

                        L.npmap.util._.getElementsByClassName("leaflet-control-legend")[0].innerHTML = t;

                        if (e) { e(); }
                    },
                    url: "https://carto.nps.gov/user/nps-yell/api/v2/sql?cb=" + (new Date).getTime() + "&q=SELECT message,npmap_id FROM road_messages WHERE archived=false"
                });
            }
        }, 100);
    }
},

// ---------------------------------------------------------------------------
// Handlers
// ---------------------------------------------------------------------------
Handlers = {
    handleReady: function() {
        // Store layer data on App for later reference, then increment ready count
        App[this.options.name.toLowerCase()] = this.getLayers();
        App.ready++;

        // Force full opacity on road lines — NPMap.js defaults to 0.5
        if (this.options.name === "Roads") {
            this.getLayers().forEach(function(layer) {
                layer.setStyle({ opacity: 0.8 });
            });
        }
    }
},

// ---------------------------------------------------------------------------
// NPMap configuration
// ---------------------------------------------------------------------------
NPMap = {
    attributionControl: !1,
    baseLayers: ["nps-parkTiles"],
    center: {
        lat: 44.65,
        lng: -110.3865
    },
    div: "map",
    hooks: {
        init: App.loadOverlays
    },
    legendControl: {
        position: "bottomright"
    },
    maxBounds: [[43.39707, -113.47229], [45.77519, -108.17163]],
    maxZoom: 12,
    minZoom: 9,
    scaleControl: !0,
    zoom: 9
};

// Bootstrap NPMap.js — must be last
s.src = "https://www.nps.gov/lib/npmap.js/4.2.1/npmap-bootstrap.min.js";
document.body.appendChild(s);
